if bTakingDamage=false and other.bCanDealDamage=true and atkProg=2 and life>0
{
  if image_xscale=1
  {
    if moveSpd>=3 {moveSpd=0}
    else if moveSpd>=-5 {moveSpd-=1.5}
  }
  else
  {
    if moveSpd<=-3 {moveSpd=0}
    else if moveSpd<=5 {moveSpd+=1.5}
  }
}
